import type { ComponentProps, ComponentRef } from 'react';
import { Accordion as AccordionPrimitive } from '@base-ui/react/accordion';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { PlusIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Accordion.module.css';

const Accordion = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Root>,
  AccordionPrimitive.Root.Props
>(function Accordion({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Root
      ref={ref}
      data-slot="accordion-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    />
  );
});

const AccordionItem = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Item>,
  AccordionPrimitive.Item.Props
>(function AccordionItem({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Item
      ref={ref}
      data-slot="accordion-item"
      className={mergeClassName(className, styles.item)}
      {...props}
    />
  );
});

const AccordionHeader = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Header>,
  AccordionPrimitive.Header.Props
>(function AccordionHeader({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Header
      ref={ref}
      data-slot="accordion-header"
      className={mergeClassName(className, styles.header)}
      {...props}
    />
  );
});

const AccordionTrigger = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Trigger>,
  AccordionPrimitive.Trigger.Props
>(function AccordionTrigger({ className, render, ...props }, ref) {
  return (
    <AccordionPrimitive.Trigger
      ref={ref}
      data-slot="accordion-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    />
  );
});

function AccordionTriggerIcon({
  className,
  children,
  'aria-hidden': ariaHidden = true,
  ...props
}: ComponentProps<'span'>) {
  return (
    <span
      data-slot="accordion-trigger-icon"
      aria-hidden={ariaHidden}
      className={clsx(styles.triggerIcon, className)}
      {...props}
    >
      {children ?? <PlusIcon />}
    </span>
  );
}

const AccordionPanel = forwardRef<
  ComponentRef<typeof AccordionPrimitive.Panel>,
  AccordionPrimitive.Panel.Props
>(function AccordionPanel({ className, ...props }, ref) {
  return (
    <AccordionPrimitive.Panel
      ref={ref}
      data-slot="accordion-panel"
      className={mergeClassName(className, styles.panel)}
      {...props}
    />
  );
});

export {
  Accordion,
  AccordionItem,
  AccordionHeader,
  AccordionTrigger,
  AccordionTriggerIcon,
  AccordionPanel,
};

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--accordion-width, 22rem);
    max-width: var(--accordion-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    color: var(--accordion-color, var(--color-foreground));
  }

  .item {
    &:not(:last-child) {
      border-bottom: var(--accordion-item-border-width, var(--border-width-sm)) solid
        var(--accordion-item-border-color, var(--color-border));
    }
  }

  .header {
    margin: 0;
  }

  .trigger {
    box-sizing: border-box;
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: space-between;
    gap: var(--accordion-trigger-gap, var(--spacing-4));
    margin: 0;
    padding-block: var(--accordion-trigger-padding-y, var(--spacing-2));
    padding-inline: var(--accordion-trigger-padding-x, var(--spacing-3));
    border: 0;
    background-color: var(--accordion-trigger-bg, var(--color-muted));
    color: inherit;
    font: inherit;
    font-size: var(--accordion-trigger-font-size, var(--text-md));
    line-height: var(--accordion-trigger-line-height, var(--line-height-text-md));
    text-align: left;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      color var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--accordion-trigger-bg-hover, var(--color-accent));
      }
    }

    &:focus-visible {
      position: relative;
      z-index: 1;
      outline: var(--accordion-focus-ring-width, var(--border-width-md)) solid
        var(--accordion-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--accordion-focus-ring-offset, var(--border-width-sm)) * -1);
    }

    &:is([disabled], [data-disabled]) {
      cursor: default;
      opacity: var(--accordion-disabled-opacity, var(--opacity-disabled));
    }
  }

  .triggerIcon {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--accordion-icon-size, 0.75rem);
    height: var(--accordion-icon-size, 0.75rem);
    flex-shrink: 0;
    transition: transform var(--accordion-icon-transition, var(--transition-default));

    & svg {
      width: 100%;
      height: 100%;
    }

    [data-panel-open] & {
      transform: var(--accordion-icon-open-transform, rotate(45deg) scale(1.1));
    }
  }

  .panel {
    box-sizing: border-box;
    height: var(--accordion-panel-height);
    overflow: hidden;
    color: var(--accordion-panel-color, var(--color-muted-foreground));
    font-size: var(--accordion-panel-font-size, var(--text-md));
    line-height: var(--accordion-panel-line-height, var(--line-height-text-md));

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }

    transition:
      height var(--accordion-panel-transition, var(--transition-default)),
      opacity var(--accordion-panel-transition, var(--transition-default)),
      transform var(--accordion-panel-transition, var(--transition-default)),
      translate var(--accordion-panel-transition, var(--transition-default));

    &[data-starting-style] {
      height: var(--accordion-panel-starting-height, 0);
      opacity: var(--accordion-panel-starting-opacity, 1);
      translate: var(--accordion-panel-starting-translate-x, 0)
        var(--accordion-panel-starting-translate-y, 0);
      transform: scale(var(--accordion-panel-starting-scale, 1));
    }

    &[data-ending-style] {
      height: var(--accordion-panel-ending-height, 0);
      opacity: var(--accordion-panel-ending-opacity, 1);
      translate: var(--accordion-panel-ending-translate-x, 0)
        var(--accordion-panel-ending-translate-y, 0);
      transform: scale(var(--accordion-panel-ending-scale, 1));
    }
  }
}

export {
  Accordion,
  AccordionItem,
  AccordionHeader,
  AccordionTrigger,
  AccordionTriggerIcon,
  AccordionPanel,
} from './Accordion';
